#include <stdio.h>
#include <string.h>

#define MAX_T 1010
#define MAX_M 110
inline int fast_read() {
int x = 0, f = 1;
char ch = getchar();
while (ch < '0' || ch > '9') { // 跳过非数字字符
if (ch == '-') f = -1; // 处理负数
ch = getchar();
}
while (ch >= '0' && ch <= '9') { // 转换数字
x = x * 10 + (ch - '0');
ch = getchar();
}
return x * f;
}

int dp[MAX_T];

int main() {
    int T, M;
    scanf("%d %d", &T, &M);

    int t[MAX_M], v[MAX_M];
    for (int i = 1; i <= M; i++) {
        t[i]=fast_read(),v[i]=fast_read();
    }

    memset(dp, 0, sizeof(dp));

    for (int i = 1; i <= M; i++) {
        for (int j = T; j >= t[i]; j--) {
            if (dp[j - t[i]] + v[i] > dp[j]) {
                dp[j] = dp[j - t[i]] + v[i];
            }
        }
    }
    printf("%d\n", dp[T]);

    return 0;
}
